const express = require('express');
const axios = require('axios');

const app = express();
app.use(express.json());

app.post('/api/wallet/create', async (req, res) => {
    const { ninNumber, faceLivelinessRef } = req.body;

    if (!ninNumber) {
        return res.status(400).json({ error: 'ninNumber is required' });
    }

    try {
        const response = await axios.post('https://api.prembly.com/verification/nin', {
            number: ninNumber
        }, {
            headers: {
                'app-id': process.env.PREMBLY_APP_ID,
                'x-api-key': process.env.PREMBLY_API_KEY
            }
        });

        return res.status(201).json({ wallet_id: 'new_wallet_123' });
    } catch (error) {
        return res.status(400).json({ error: 'Verification failed' });
    }
});

const PORT = 3000;
app.listen(PORT, () => {
    console.log(`Server is running on port ${PORT}`);
});

